import json
import os
from datetime import datetime
from typing import Any

HISTORY_FILE_PATH = os.path.join("outputs", "history.jsonl")


def _ensure_history_file() -> None:
    os.makedirs("outputs", exist_ok=True)
    if not os.path.exists(HISTORY_FILE_PATH):
        with open(HISTORY_FILE_PATH, "w", encoding="utf-8"):
            pass


def append_history(entry: dict[str, Any]) -> None:
    _ensure_history_file()
    payload = {
        "timestamp": datetime.utcnow().isoformat() + "Z",
        **entry,
    }
    with open(HISTORY_FILE_PATH, "a", encoding="utf-8") as file:
        file.write(json.dumps(payload, ensure_ascii=True) + "\n")


def get_history(limit: int = 100) -> list[dict[str, Any]]:
    _ensure_history_file()
    with open(HISTORY_FILE_PATH, "r", encoding="utf-8") as file:
        lines = [line.strip() for line in file if line.strip()]

    parsed: list[dict[str, Any]] = []
    for line in reversed(lines[-limit:]):
        try:
            parsed.append(json.loads(line))
        except json.JSONDecodeError:
            continue
    return parsed

    enhanced_prompt = str(parsed.get("enhanced_prompt", "")).strip()
    negative_prompt = str(parsed.get("negative_prompt", "")).strip()
    if not enhanced_prompt:
        raise ValueError("Ollama returned empty enhanced_prompt")
    return enhanced_prompt, negative_prompt


def enhance_prompt(prompt: str) -> tuple[str, str, str]:
    try:
        enhanced_prompt, negative_prompt = _call_ollama(prompt)
        provider = f"ollama:{OLLAMA_MODEL}"
    except (URLError, TimeoutError, ValueError, json.JSONDecodeError, OSError):
        enhanced_prompt, negative_prompt = _fallback_enhancement(prompt)
        provider = "fallback:rule-based"

    return enhanced_prompt, negative_prompt, provider

